import{_ as a,o as l,c as i,ae as o}from"./chunks/framework.C7FLYIpo.js";const u=JSON.parse('{"title":"스크립트","description":"리포지토리 스크립트: 목적, 범위, 안전 참고 사항","frontmatter":{"title":"스크립트","description":"리포지토리 스크립트: 목적, 범위, 안전 참고 사항"},"headers":[],"relativePath":"help/scripts.md","filePath":"help/scripts.md","lastUpdated":null}'),t={name:"help/scripts.md"};function c(r,e,d,s,p,n){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="스크립트" tabindex="-1">스크립트 <a class="header-anchor" href="#스크립트" aria-label="Permalink to &quot;스크립트&quot;">​</a></h1><p><code>scripts/</code> 디렉토리에는 로컬 워크플로우 및 운영 작업을 위한 헬퍼 스크립트가 포함되어 있습니다. 작업이 스크립트와 명확히 연관된 경우에 사용하십시오. 그렇지 않은 경우 CLI를 사용하는 것이 좋습니다.</p><h2 id="규칙" tabindex="-1">규칙 <a class="header-anchor" href="#규칙" aria-label="Permalink to &quot;규칙&quot;">​</a></h2><ul><li>스크립트는 문서나 릴리스 체크리스트에서 참조되지 않는 한 <strong>선택 사항</strong>입니다.</li><li>가능한 경우 CLI 인터페이스를 사용하십시오 (예: 인증 모니터링은 <code>openclaw models status --check</code> 사용).</li><li>스크립트는 호스트별로 다를 수 있으므로 새 머신에서 실행하기 전에 먼저 읽어 보십시오.</li></ul><h2 id="인증-모니터링-스크립트" tabindex="-1">인증 모니터링 스크립트 <a class="header-anchor" href="#인증-모니터링-스크립트" aria-label="Permalink to &quot;인증 모니터링 스크립트&quot;">​</a></h2><p>인증 모니터링은 <a href="/openclaw-docs-ko/gateway/authentication">인증</a>에서 다룹니다. <code>scripts/</code> 아래의 스크립트는 systemd/Termux 전화 워크플로우를 위한 선택적 추가 기능입니다.</p><h2 id="github-읽기-헬퍼" tabindex="-1">GitHub 읽기 헬퍼 <a class="header-anchor" href="#github-읽기-헬퍼" aria-label="Permalink to &quot;GitHub 읽기 헬퍼&quot;">​</a></h2><p>일반적인 쓰기 작업에는 개인 로그인을 사용하는 <code>gh</code>를 남겨두면서 리포지토리 범위의 읽기 호출에 GitHub App 설치 토큰을 사용하려면 <code>scripts/gh-read</code>를 사용하십시오.</p><p>필수 환경 변수:</p><ul><li><code>OPENCLAW_GH_READ_APP_ID</code></li><li><code>OPENCLAW_GH_READ_PRIVATE_KEY_FILE</code></li></ul><p>선택적 환경 변수:</p><ul><li><code>OPENCLAW_GH_READ_INSTALLATION_ID</code> — 리포지토리 기반 설치 조회를 건너뛰려는 경우</li><li><code>OPENCLAW_GH_READ_PERMISSIONS</code> — 요청할 읽기 권한 하위 집합의 쉼표 구분 재정의</li></ul><p>리포지토리 확인 순서:</p><ul><li><code>gh ... -R owner/repo</code></li><li><code>GH_REPO</code></li><li><code>git remote origin</code></li></ul><p>예시:</p><ul><li><code>scripts/gh-read pr view 123</code></li><li><code>scripts/gh-read run list -R openclaw/openclaw</code></li><li><code>scripts/gh-read api repos/openclaw/openclaw/pulls/123</code></li></ul><h2 id="스크립트-추가-시" tabindex="-1">스크립트 추가 시 <a class="header-anchor" href="#스크립트-추가-시" aria-label="Permalink to &quot;스크립트 추가 시&quot;">​</a></h2><ul><li>스크립트를 집중적으로 작성하고 문서화하십시오.</li><li>관련 문서에 짧은 항목을 추가하십시오 (없으면 새로 만드십시오).</li></ul>',18)])])}const _=a(t,[["render",c]]);export{u as __pageData,_ as default};
